#include<bits/stdc++.h>
typedef long long ll;
using namespace std;
const int N=1000010;
int n;
ll a[N],maxl[N],maxr[N];
ll sum,cut;
void solve()
{
	cin>>n;
	sum=cut=0;
    maxr[n+1]=0;
	for(int i=1;i<=n;i++)
    {
		cin>>a[i];
		maxl[i]=max(maxl[i-1],a[i]);
	}
	for(int i=n;i>=1;i--){
		maxr[i]=max(maxr[i+1],a[i]);
	}
	for(int i=1;i<=n;i++)
    {
		ll t=min(maxl[i-1],maxr[i+1]);
		if(t>a[i])
        {
			sum+=t-a[i];
			cut=max(cut,t-a[i]);
		}
	}
	int l=1,r=2;
	while(r<=n)
    {
		ll low=maxl[l-1],cnt=0;
		while(a[r]<a[l])
        {
			ll w=min(maxl[r-1],maxr[r+1]);
			if(w>max(low,a[r]))cnt+=w-max(low,a[r]);
			low=max(low,a[r]);
			r++;
			if(r==n+1)break;
		}
		cut=max(cut,cnt);
		l=r;r++;
	}
	r=n,l=n-1;
	while(l>=1)
    {
		ll low=maxr[r+1],cnt=0;
		while(a[l]<a[r])
        {
			ll w=min(maxl[l-1],maxr[l+1]);
			if(w>max(low,a[l]))cnt+=w-max(low,a[l]);
			low=max(low,a[l]);
			l--;
			if(l==0)break;
		}
		cut=max(cut,cnt);
		r=l;l--;
	}
	cout<<sum-cut<<'\n';
}
int main()
{
	int T;
	cin>>T;
	while(T--)
    {
		solve();
	}	
	return 0;
}
